PTMPL = "plotly_dark"
PLOT_BG = "#0d1117"
PAPER_BG = "#0d1117"
GRID_COLOR = "#30363d"
FONT_COLOR = "#ffffff"

def dark_layout(fig, height=380):
    fig.update_layout(
        template=PTMPL, height=height,
        plot_bgcolor=PLOT_BG, paper_bgcolor=PAPER_BG,
        font=dict(color=FONT_COLOR, size=12),
        margin=dict(t=40, b=20, l=10, r=10),
        legend=dict(bgcolor="#161b22", bordercolor="#30363d", borderwidth=1, font=dict(color="#ffffff")),
        xaxis=dict(gridcolor=GRID_COLOR, linecolor="#30363d", tickfont=dict(color="#ffffff"), title_font=dict(color="#ffffff")),
        yaxis=dict(gridcolor=GRID_COLOR, linecolor="#30363d", tickfont=dict(color="#ffffff"), title_font=dict(color="#ffffff")),
    )
    return fig

BLUES  = ["#1e3a5f","#1d4e89","#2563a8","#3b82c4","#58a6ff","#79b8ff","#a5d0ff"]
MULTI  = ["#58a6ff","#3fb950","#f78166","#d2a8ff","#ffa657","#76e3ea","#ff7b72"]
GREEN  = "#3fb950"
RED    = "#f85149"
ORANGE = "#e3b341"
CYAN   = "#58a6ff"

@st.cache_data
def load_data():
    def d(s): return pd.read_csv(io.StringIO(base64.b64decode(s).decode()))
    return (d(""),d(""),d(""),d(""),
            d(""),d(""),d(""),
            d(""),d(""),d("TU9EVUxPLENsYXNlcwoxLjAsNjk5CjIuMCwxMDc2CjMuMCwxMDY4CjQuMCw0OTYKNS4wLDY4MAo2LjAsNzE1CjcuMCwzNTcK"),
            d(""),d(""),d(""))

df_res,df_det,df_fac,df_doc,df_cd,df_cs,df_ef_fac,df_ef_ed,df_ef_det,df_cm,df_cfm,df_ct,df_rev = load_data()

MODULOS = {1:"M1·08:15",2:"M2·09:45",3:"M3·11:15",4:"M4·12:45",5:"M5·14:15",6:"M6·15:45",7:"M7·17:15"}
MODULOS_FULL = {1:"Mód 1 · 08:15–09:35",2:"Mód 2 · 09:45–11:05",3:"Mód 3 · 11:15–12:35",4:"Mód 4 · 12:45–14:05",5:"Mód 5 · 14:15–15:35",6:"Mód 6 · 15:45–17:05",7:"Mód 7 · 17:15–18:35"}
ED_SHORT = {"GONZALO HERNANDEZ URIBE TORRE B":"G.H. Torre B","GONZALO HERNANDEZ URIBE TORRE C":"G.H. Torre C",
    "GONZALO HERNANDEZ URIBE TORRE D":"G.H. Torre D","VICENTE KOVACEVIC I":"V. Kovacevic I","VICENTE KOVACEVIC II":"V. Kovacevic II"}
FAC_SHORT = {"FACULTAD DE MEDICINA Y CIENCIAS DE LA SALUD":"Medicina","FACULTAD DE INGENIERÍA":"Ingeniería",
    "VICERRECTORÍA ACADÉMICA":"Vicerrectoría","FACULTAD DE CIENCIAS DE LA EDUCACIÓN":"Educación",
    "FACULTAD DE DERECHO Y HUMANIDADES":"Derecho","FACULTAD DE ECONOMÍA, GOBIERNO Y COMUNICACIONES":"Econ./Gob./Com.",
    "FACULTAD DE GOBIERNO":"Gobierno","FACULTAD DE ARQUITECTURA, URBANISMO Y PAISAJE":"Arquitectura","INSTITUTO DE CARRERAS TÉCNICAS":"ICIT"}
DIAS_ORDER = ["Lunes","Martes","Miércoles","Jueves","Viernes"]
RANGO_ORDER = ["≤20 pax","21-30 pax","31-40 pax","41-50 pax","51+ pax"]
EFCAT_ORDER = ["Muy baja (<30%)","Baja (30-50%)","Media (50-70%)","Alta (70-90%)","Óptima/Exceso (>90%)"]

for df, col, mapping in [
    (df_res,"Ed_corto",ED_SHORT),(df_det,"Ed_corto",ED_SHORT),
    (df_fac,"Fac_corto",FAC_SHORT),(df_cfm,"Fac_corto",FAC_SHORT),
    (df_ct,"Fac_corto",FAC_SHORT),(df_ef_fac,"Fac_corto",FAC_SHORT),(df_doc,"Fac_corto",FAC_SHORT),
]:
    src = "Edificio" if col=="Ed_corto" else "Facultad" if "Facultad" in df.columns else "FACULTAD"
    df[col] = df[src].map(mapping).fillna(df[src])

df_res["Dia"] = pd.Categorical(df_res["Dia"], categories=DIAS_ORDER, ordered=True)
df_det["Dia"] = pd.Categorical(df_det["Dia"], categories=DIAS_ORDER, ordered=True)

ocup_ed_df = df_res.drop_duplicates("Edificio")[["Ed_corto","Pct_Global_Edificio","Bloques_Posibles_Ed","Bloques_Ocupados_Ed"]].copy()
global_total_ocp = ocup_ed_df["Bloques_Ocupados_Ed"].sum()
global_total_pos = ocup_ed_df["Bloques_Posibles_Ed"].sum()
PCT_GLOBAL = round(global_total_ocp/global_total_pos*100,1)

st.sidebar.markdown("## 🔎 Filtros")
edificios_opts = list(ED_SHORT.values())
sel_ed = st.sidebar.multiselect("Edificio", edificios_opts, default=edificios_opts)
sel_dias = st.sidebar.multiselect("Día", DIAS_ORDER, default=DIAS_ORDER)
sel_mods = st.sidebar.multiselect("Módulo", list(MODULOS.keys()), format_func=lambda x: MODULOS_FULL[x], default=list(MODULOS.keys()))

fr = df_res[df_res["Ed_corto"].isin(sel_ed)&df_res["Dia"].isin(sel_dias)&df_res["Modulo"].isin(sel_mods)].copy()
fd = df_det[df_det["Ed_corto"].isin(sel_ed)&df_det["Dia"].isin(sel_dias)&df_det["Modulo"].isin(sel_mods)].copy()

